// // This module implements a 2-to-1 multiplexer with an enable input. The module has two 1-bit inputs (A and B), an enable input (EN), and a 1-bit output (Y). When EN is high, Y should be equal to A. When EN is low, Y should be equal to B.
module mux_2to1_enable (
    input A,
    input B,
    input EN,
    output reg Y
);

always @ (A, B, EN) begin
    if (EN == 1'b0) begin
        Y = A;
    end else begin
        Y = B;
    end
end

endmodule
